import{_ as a,o as t,c as i,ae as n}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Deep Linking for Developers","description":"","frontmatter":{"title":"Deep Linking for Developers","slug":"technical-deep-linking-for-developers"},"headers":[],"relativePath":"developer-hub/technical-deep-linking-for-developers.md","filePath":"developer-hub/technical-deep-linking-for-developers.md"}'),o={name:"developer-hub/technical-deep-linking-for-developers.md"};function r(l,e,h,s,d,p){return t(),i("div",null,[...e[0]||(e[0]=[n('<p>.png &quot;Contextual_Deep_Link.png&quot;)</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Branch deep linking gives you peace of mind that your links will work in every edge case to route users to the best destination with the industry&#39;s highest matching accuracy, by combining every deep linking standard into a single, simple package. Easy to implement, and always up to date.</p><h3 id="deep-linking-use-cases" tabindex="-1">Deep linking use cases: <a class="header-anchor" href="#deep-linking-use-cases" aria-label="Permalink to &quot;Deep linking use cases:&quot;">​</a></h3><ul><li>Direct deep linking users who have the app installed already to relevant content.</li><li>Deferred deep linking users who do not have the app installed to relevant content immediately after the first install.</li><li>Customized/branded URLs.</li><li>Store custom data parameters in link data.</li></ul><h2 id="how-does-it-work" tabindex="-1">How does it work? <a class="header-anchor" href="#how-does-it-work" aria-label="Permalink to &quot;How does it work?&quot;">​</a></h2><ol><li><p>User clicks a link.</p><ol><li><p>If user has the app installed, then the app opens and routes to relevant content.</p></li><li><p>If user doesn&#39;t have the app installed, then:</p><ol><li>User is routed to App/Play store to download the app, then routed to relevant content when they open the app, or</li><li>User is routed to relevant mobile web content.</li></ol></li></ol></li></ol><h2 id="integration-guide" tabindex="-1">Integration guide <a class="header-anchor" href="#integration-guide" aria-label="Permalink to &quot;Integration guide&quot;">​</a></h2><h4 id="_1-implement-the-branch-sdks-to-your-mobile-app" tabindex="-1">1. Implement the Branch SDKs to your mobile app <a class="header-anchor" href="#_1-implement-the-branch-sdks-to-your-mobile-app" aria-label="Permalink to &quot;1. Implement the Branch SDKs to your mobile app&quot;">​</a></h4><p>Please visit our <a href="https://help.branch.io/developers-hub/docs/native-sdks-overview" target="_blank" rel="noreferrer">Native SDK Overview page</a> to learn how to implement the Branch SDK on both iOS and Android.</p><h4 id="_2-set-up-deep-link-routing" tabindex="-1">2. Set up deep link routing <a class="header-anchor" href="#_2-set-up-deep-link-routing" aria-label="Permalink to &quot;2. Set up deep link routing&quot;">​</a></h4><p>How your mobile app is routing to in-app content will determine how you will create and tag your Branch Links.</p><ul><li><a href="./in-app-routing.html#option-1-build-custom-routing-inside-the-routing-callback">Build custom routing inside the routing callback</a></li><li><a href="./in-app-routing.html#option-2-let-branch-use-your-existing-deep-link-routing">Let Branch use your existing deep link routing</a></li></ul><h4 id="_3-create-your-branch-link" tabindex="-1">3. Create your Branch Link <a class="header-anchor" href="#_3-create-your-branch-link" aria-label="Permalink to &quot;3. Create your Branch Link&quot;">​</a></h4><p>Branch Link creation options:</p><ul><li><p><a href="./create-quick-links.html">Short Link</a></p><ul><li>Ideal for one-off campaigns, especially social media, blog posts, etc.</li></ul></li><li><p><a href="./deep-linking-api.html">Deep Linking API</a></p><ul><li>Ideal if you are looking to programmatically generate Branch Links at scale.</li></ul></li><li><p><a href="./native-sdks-overview.html">Mobile SDKs</a></p></li><li><p><a href="./web-sdk-overview.html">Web SDK</a></p></li><li><p><a href="https://chrome.google.com/webstore/detail/branch-link-creator/pekdpppibljpmpbcjelehhnldnfbglgf" target="_blank" rel="noreferrer">Chrome Extension</a></p></li></ul><h4 id="_4-configure-your-branch-link" tabindex="-1">4. Configure your Branch Link <a class="header-anchor" href="#_4-configure-your-branch-link" aria-label="Permalink to &quot;4. Configure your Branch Link&quot;">​</a></h4><p>When configuring your Branch Link you must make sure you are adding the correct key/value pairs to the data dictionary to ensure they make it into the app when it opens from a Branch Link click.</p><p>.png &quot;Screen Shot 2021-09-28 at 1.42.10 PM.png&quot;)Additional details on configuring your Branch Link can be found <a href="./creating-a-deep-link.html">here</a>.</p><h4 id="_5-test-your-branch-link" tabindex="-1">5. Test your Branch Link <a class="header-anchor" href="#_5-test-your-branch-link" aria-label="Permalink to &quot;5. Test your Branch Link&quot;">​</a></h4><p>Click the Branch Link on your mobile device and it should go through the flow outlined on the <a href="./deep-linking.html#how-does-it-work">How Does It Work?</a> page.</p><h4 id="_6-set-up-nativelinktm-deferred-deep-linking-optional" tabindex="-1">6. Set up NativeLink™ Deferred Deep Linking (optional) <a class="header-anchor" href="#_6-set-up-nativelinktm-deferred-deep-linking-optional" aria-label="Permalink to &quot;6. Set up NativeLink™ Deferred Deep Linking (optional)&quot;">​</a></h4><p>For NativeLink™ Deferred Deep Linking, please follow our guide <a href="./nativelink-deferred-deep-linking.html">here</a>.</p><h2 id="best-practices" tabindex="-1">Best practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best practices&quot;">​</a></h2><h3 id="deep-link-routing-with-canonical-url" tabindex="-1">Deep link routing with <code>$canonical_url</code> <a class="header-anchor" href="#deep-link-routing-with-canonical-url" aria-label="Permalink to &quot;Deep link routing with `$canonical_url`&quot;">​</a></h3><p>A canonical URL is a Branch referred term that represents the corresponding web URL for the in-app content. If your app can already deep link using web URLs, it is recommended to use the $canonical_url key with the web URLs value for deep linked routing for the app. This reduces the level of effort as $canonical_url is often automatically applied as Branch Link data for products like Journeys and Email; therefore, there is not an additional need to add extra data to a link.</p><p>For example, a shopping brand that has both a website and a mobile app will have equivalent experiences for the user to get to related content and it can be identified with a canonical URL. A web URL might look something like this:</p><p><code>https://www.myshop.com/category/productName</code></p><p>For a hotel/travel brand, a canonical URL might look something like this:</p><p><code>https://www.mytravel.com/Hotel-Search?rooms=1&amp;adults=2&amp;destination=Bangkok%20(BKK%20-%20Suvarnabhumi%20Intl.)&amp;regionId=4934466&amp;latLong=13.687353%2C100.74995&amp;startDate=2021-09-23&amp;endDate=2021-09-24&amp;d1=2021-09-23&amp;d2=2021-09-24</code></p><p>The different parts of the URL can be used for deep linking the user to in-app content.</p><h3 id="open-graph-tags-in-branch-links" tabindex="-1">Open Graph tags in Branch Links <a class="header-anchor" href="#open-graph-tags-in-branch-links" aria-label="Permalink to &quot;Open Graph tags in Branch Links&quot;">​</a></h3><p>When creating your Branch Link, you can add <a href="https://ogp.me/" target="_blank" rel="noreferrer">Open Graph</a> tags to enhance its look and feel in a social graph. Adding these tags should make your Branch Link look better in channels like SMS or on social media posts. The following tags can be used in your Branch Link:</p><table tabindex="0"><thead><tr><th>Open Graph Key</th><th>Description</th></tr></thead><tbody><tr><td><code>$og_title</code></td><td>The title of your object as it should appear within the graph.</td></tr><tr><td><code>$og_description</code></td><td>A one to two sentence description of your object.</td></tr><tr><td><code>$og_image_url</code></td><td>An image URL which should represent your object within the graph.</td></tr></tbody></table><p>This is automatically set when setting the Social Media Tags if you are creating a Branch Short Link or scraped when setting <code>$original_url</code>, <code>$desktop_url</code>, or <code>$fallback_url</code>.</p><div class="warning custom-block"><p class="custom-block-title">Caution</p><p><code>$original_url</code> is set in the Link Template, which will automatically add the <code>$canonical_url</code> with the same value. However, <code>$canonical_url</code> is NOT directly scraped for setting the Social Media Tags.</p></div><p>.png &quot;Screen Shot 2021-09-28 at 2.22.55 PM.png&quot;)</p><h2 id="testing-and-troubleshooting" tabindex="-1">Testing and troubleshooting <a class="header-anchor" href="#testing-and-troubleshooting" aria-label="Permalink to &quot;Testing and troubleshooting&quot;">​</a></h2><p>Please use the following guides for testing and troubleshooting your deep links:</p><ul><li><p>Android</p><ul><li><a href="./android-testing.html">Testing</a></li><li><a href="./android-troubleshooting.html">Troubleshooting</a></li></ul></li><li><p>iOS</p><ul><li><a href="./ios-testing.html">Testing</a></li><li><a href="./ios-troubleshooting.html">Troubleshooting</a></li></ul></li></ul>',40)])])}const g=a(o,[["render",r]]);export{u as __pageData,g as default};
